var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리는 반드시 이 도시를 지켜야……","JPN":"私たちは必ずこの都市を守らねば……","ENG":"We must protect this city no matter what...","TWN":"我們一定要守住這座城市……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"허신이 사라졌다고……?","JPN":"虚神が消えただと……？","ENG":"The Hollow God is gone...?","TWN":"虛神消失了……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"제6종 침식체, 시그널 로스트……!","JPN":"第6種侵食体、シグナルロスト……！","ENG":"Category 6 C.O., signal lost...!","TWN":"第6類侵蝕體，喪失訊號……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스, 현장에서 무슨 일이 있었던 거야? 정말로 허신을 토벌했다고?","JPN":"オジマンディアス、現場で何があった？　本当に虚神を討伐したのか？","ENG":"Ozymandias, what happened on site? Did you really defeat the Hollow God?","TWN":"奧茲曼迪亞斯，現場究竟發生什麼事了？真的除掉虛神了嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내, 낸들 알아!? 갑자기 녀석이 증발해 버렸다고!","JPN":"し、知らないわよ！　いきなり目の前で消えちゃったし！","ENG":"How would I know?! It just evaporated out of nowhere!","TWN":"我、我怎麼會知道！？那傢伙突然就蒸發了啊！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마, 다른 차원으로 도망간 건가? 하지만 어째서……?","JPN":"まさか、別の次元に逃げた？　でもどうして……？","ENG":"Did it escape to another dimension? But why...?","TWN":"難道是逃往其他次元了？但怎麼會……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"아니요, 허신은 소멸했습니다.","JPN":"いいえ、虚神は消滅しました。","ENG":"No. The Hollow God has been annihilated.","TWN":"不，已經消滅虛神了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다, 당신은……?","JPN":"あ、あなたは……？","ENG":"Y-you're...?","TWN":"你、你是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제가 누구인지는 중요하지 않겠죠.","JPN":"私が誰か、それは今重要ではありませんわ。","ENG":"Who I am is not important.","TWN":"我是誰並不重要。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 이것의 부름에 이끌려, 제 영지를 둘러보고 있었을 뿐이니까요.","JPN":"私はこれの呼びかけに導かれ、自分の領地を見回っていただけです。","ENG":"I was merely drawn here by its call and surveying my estate.","TWN":"我只是受到這個的呼喚，順道巡視了一下自己的領地而已。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭔데, 그 촌스러운 그 깡통 새는……?","JPN":"何なの、そのダサいボロ缶カラスは……？","ENG":"What's with that tacky tin can bird?","TWN":"那隻土土的罐裝鳥是什麼……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어라, 왠지 디자인이 낯이 익은데?","JPN":"あれ、なんか見覚えのあるデザインだな？","ENG":"Huh? The design feels strangely familiar.","TWN":"咦，我總覺得這設計有點眼熟？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"서, 설마? 코치……?","JPN":"えっ、待って……コーチ……？","ENG":"W-wait... Is that Coach...?","TWN":"難、難道說？是教練……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그보다 대균열이 더 확장되기 전에, 서두르는 게 좋을 겁니다.","JPN":"それより、大亀裂がこれ以上拡張する前に急いだほうがいいですわ。","ENG":"We should hurry before the Grand Dimension Crevice expands any further.","TWN":"比起這個，在大峽谷進一步擴張前最好快點行動。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"허신이 쓰러진 지금이라면, 그 장치를 발동시킬 수 있을 테니까요.","JPN":"虚神が倒れた今なら、あの装置を稼働できるはずです。","ENG":"Now that the Hollow God has fallen, the device should be operable.","TWN":"現在虛神已被擊倒，應該能啟動那個裝置了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"무언가 말 못할 사정이 있는 모양이지만…….","JPN":"何か口にできない事情があるようだが……","ENG":"It seems you have circumstances you cannot speak of...","TWN":"看來你似乎有什麼難言之隱……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그대가 이곳에 있다는 것 또한 최고 관리자의 구상이겠지.","JPN":"君がここにいることもまた、最高管理者の策のうちなんだろうな。","ENG":"But your presence here must also be part of the Supreme Administrator's design.","TWN":"不過，你會出現在這裡，應該也是最高管理者的安排吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그렇다면, 이 전장을 이끄는 선봉장으로서 그대에게 감사를 표하지.","JPN":"ならば、この戦場を率いる先鋒隊長として君に礼を言わせてくれ。","ENG":"If so, as the vanguard leading this battlefield, I offer you my thanks.","TWN":"既然如此，作為引領這個戰場的先鋒指揮官，我向你致上謝意。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흠, 뭔가 께름칙하지만…….","JPN":"ふむ、どうもすっきりしないところはあるが……","ENG":"It feels unsettling, but...","TWN":"嗯，雖然總覺得哪裡不太對勁……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이제 더는 망설일 시간이 없어.","JPN":"今は躊躇っている場合ではない。","ENG":"There's no time left to hesitate.","TWN":"但已經沒有時間猶豫了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 히페리온!","JPN":"よし、ハイペリオン！","ENG":"All right, Hyperion!","TWN":"好，海柏利昂！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"목표 지점에 선로전환기를 사출……!","JPN":"目標地点に線路転換器を射出……！","ENG":"Launch the Track Switcher at the target point...!","TWN":"向目標地點射出軌道轉換器……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"얼마든지 맡겨주게! 시니어 르네!","JPN":"どんと任せてくれ！　シニア・ルネ！","ENG":"Leave it to me! Senior Renée!","TWN":"儘管交給我吧！Senior芮妮！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"선로전환기 사출……!","JPN":"線路転換器、射出……！","ENG":"Launching the Track Switcher...!","TWN":"軌道轉換器射出……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"자, 모두들 서둘러……!","JPN":"皆、急いでくれ……！","ENG":"Everyone, move quickly...!","TWN":"好，大家動作快……！"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"전환기에 동력원을 연결하고, 공간이 융해되지 않도록 유산을 배치해……!","JPN":"転換器に動力源を繋いで、空間が融解しないよう遺産を配置するんだ……！","ENG":"Connect the power source to the Switcher and deploy the Legacy to prevent spatial fusion...!","TWN":"把動力源連接到轉換器，配置遺產避免空間熔解……！"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"어려운 발걸음을 하셨군요, 레지나 님.","JPN":"わざわざ足を運んでいただいたのですね、レジーナ様。","ENG":"You went through great trouble to come here, Miss Regina.","TWN":"您一路上辛苦了，蕾佳娜大人。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부디, 저희의 불충을 용서하시길…….","JPN":"どうか私たちの不甲斐なさをお許しください……","ENG":"Please forgive our disloyalty.","TWN":"請您原諒我們的不忠……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"고개를 드세요.","JPN":"顔を上げてください。","ENG":"Raise your head.","TWN":"抬起頭來吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"당신들은 공을 세웠습니다. 람다, 루시아 그리고…….","JPN":"あなたたちは功績を上げましたわ。ラムダ、ルシア、そして……","ENG":"You have rendered great service, Lamda, Lucia, and...","TWN":"你們立下了功勞。蘭達、露西卡，還有……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저, 전 카타리나예요! 종교학부의……","JPN":"わ、私はカタリナです！　宗教学部の……","ENG":"I-I'm Katharina! From the Religion Department...","TWN":"我、我是卡特莉娜！宗教學院的……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"헙!?","JPN":"はっぷ！？","ENG":"Huh?!","TWN":"咦！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그래요, 카타리나.","JPN":"そう、カタリナ。","ENG":"Yes, Katharina.","TWN":"是的，卡特莉娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 긴장을 늦춰서는 안 되겠죠.","JPN":"ですが、気を緩めてはいけませんわ。","ENG":"But we cannot lower our guard yet.","TWN":"不過現在可不能放鬆警戒。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제 영지를 어지럽힌 불청객들이 아직 그 모습을 드러내지 않았습니다.","JPN":"私の領地を乱した、招かれざる客たちはまだその姿を現していません。","ENG":"The intruders who defiled my estate have yet to reveal themselves.","TWN":"擾亂我領地的不速之客，還沒有現身。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 선로전환기가 설치된 지점으로부터 반경 3km까지 경계를 늦추지 마세요.","JPN":"エデル、線路転換器が設置された地点から半径3kmまで、警戒を怠らないようお願いします。","ENG":"Edel, maintain vigilance within a 3-kilometer radius of the Track Switcher.","TWN":"艾瑟兒，以線路轉換器設置地點為中心，半徑3公里內都不要放鬆警戒。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"장치가 가동하기 위해서는 다소 시간이 필요할 겁니다.","JPN":"装置の稼働までには、多少時間がかかるでしょうから。","ENG":"The device will require some time to activate.","TWN":"還需要一點時間啟動裝置。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"예측하지 못한 사태가 벌어지면, 즉시 시간을 동결하겠어요.","JPN":"予期せぬ事態が起きた場合は、すぐに時間を凍結させますわ。","ENG":"If anything unforeseen occurs, I will freeze time immediately.","TWN":"若發生無法預測的狀況，我會立刻凍結時間。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"걱정하지 마세요, 나의 레지나 님.","JPN":"ご心配なく、我々のレジーナ様。","ENG":"Do not worry, our Regina.","TWN":"請放心，我的蕾佳娜大人。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"당신의 명령이라면, 저는 이 영지에 있는 모든 것을……","JPN":"あなたのご命令とあれば、我々はこの領地に存在するすべてを……","ENG":"At your command, we will protect everything within this estate–","TWN":"只要是您的命令，我將把這片領地中的一切……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"크읏!?","JPN":"くっ！？","ENG":"Ghk?!","TWN":"呃啊！？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ONLY_FIERCE_ESPR_KNIGHT_SKILL_1"},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"봉인 사슬, 호수의 기사로군.","JPN":"封印の鎖……湖の騎士ね。","ENG":"Sealing Chains... It's the Knight of the Lake.","TWN":"封印鎖鏈……是湖水騎士啊。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"과연, 사도가 되었어도 가아그셰블라와 대적하는 운명은 그대로라는 뜻인가?","JPN":"なるほど。使徒になってもガアグシェブラと敵対する運命は変わらないってことかしら？","ENG":"So even as an Apostle, your fate to oppose Gha'agsheblah remains unchanged.","TWN":"所以即便成為使徒，還是沒有改變與加格舍夫拉對抗的命運嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 사도라고 해도, 얼어버린 시간 속에서는 움직일 수 없어.","JPN":"でも使徒といえど、凍りついた時間の中では動けないわ。","ENG":"But even Apostles cannot move within frozen time.","TWN":"不過就算是使徒，在凍結的時間中也無法行動。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"나를 제외하고, 정지된 시간 속에서 움직일 수 있는 건, 세계를 만드는 법칙 밖에 있는 존재들뿐…….","JPN":"私を除いて、止まった時間の中で動けるのは、世界を作る法則の外側にいる存在のみ……","ENG":"Aside from me, only beings outside the law of creating a world may move in stopped time.","TWN":"除了我之外，能在靜止的時間裡行動的，只有存在於建構世界法則之外的存在……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 당신을 속박하고 있는 사슬을 끊겠습니다.","JPN":"エデル、あなたを束縛している鎖を切ります。","ENG":"Edel, I will sever the chains binding you.","TWN":"艾瑟兒，我將切斷束縛你的鎖鏈。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"봉인에서 풀려나는 즉시 호수의 기사를 찾아 제거하세요.","JPN":"封印が解かれ次第、湖の騎士を見つけ出して排除しなさい。","ENG":"The moment you are freed, locate and eliminate the Knight of the Lake.","TWN":"解除封印後，立刻找出湖水騎士並加以排除。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"어라? 그렇게는 안 될 걸요?","JPN":"あら？　そうはさせませんよ？","ENG":"Oh? I am afraid I cannot allow that.","TWN":"咦？那可不行哦？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"큭, 레지나 님! 조심하세요!","JPN":"くっ、レジーナ様！　お気をつけください！","ENG":"Ghk, Miss Regina! Be careful!","TWN":"呃，蕾佳娜大人！請小心！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮으세요, 레지나 님?","JPN":"大丈夫ですか、レジーナ様？","ENG":"Are you unharmed, Miss Regina?","TWN":"您沒事吧，蕾佳娜大人？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 괜찮아요. 하지만…….","JPN":"問題ありませんわ。ですか……","ENG":"I'm fine, but...","TWN":"我沒事，但是……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"오랜만이네요, 어머니.","JPN":"久しぶりですね、お母さん。","ENG":"It has been a while, Mother.","TWN":"好久不見了，母親。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_19"},{"id":"L50_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"보아하니, 그동안 건강하게 잘 지내신 모양이에요.","JPN":"見たところ、今まで元気でお過ごしになっていたようで何よりです。","ENG":"You seem to have been doing quite well all this time.","TWN":"看來這段時間您過得很健康呢。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"기사님의 사슬을 끊어내고, 레지나를 감쌀 정도로 힘이 넘치시니까요.","JPN":"騎士様の鎖を斬って、レジーナを庇うほど力が有り余っていますもの。","ENG":"Strong enough to break my knight's chains and shield Regina.","TWN":"不僅能斬斷騎士的鎖鏈，甚至還有餘力包覆蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"하지만 그 정도 억지를 부렸으니, 방금 걸로 조금은 파편을 소모했을까요?","JPN":"でもあれだけ無茶をしたのですから、今ので少しは破片を消耗したのではないですか？","ENG":"But forcing yourself like that, did you expend a Fragment just now?","TWN":"但既然如此衝動行事，那一下應該也消耗不少碎片了吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"감히 나의 레지나 님을 농락하다니…….","JPN":"よくも我々のレジーナ様を侮辱して……","ENG":"How dare you toy with our Regina...","TWN":"竟敢戲弄我的蕾佳娜大人……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"기대하세요, 방해자. 당신의 파편 한 조각 남기지 않고 모조리 씹어 탐식할 테니까.","JPN":"楽しみにしていなさい、邪魔者。あなたの破片は1つ残らずすべて噛み砕き、貪食しますから。","ENG":"Prepare yourself, Disturber. I will devour every last Fragment of you.","TWN":"期待吧，妨礙者。我會將你的碎片一片不留，全部咀嚼吞噬殆盡。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하, 마음이 통했네요. 어머니.","JPN":"あはっ、心が通じましたね。お母さん。","ENG":"Ah, we are thinking alike, Mother.","TWN":"啊哈，我們真是心意相通呢，母親。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저도 오늘은 마음 놓고 어머니를 미식할 생각이었거든요.","JPN":"私も今日は心置きなくお母さんを味わうつもりだったんです。","ENG":"I was planning to savor you properly today as well.","TWN":"我今天本來也打算要盡情好好品嚐母親一番呢。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"하지만 그전에…….","JPN":"でもその前に……","ENG":"But before that...","TWN":"不過在那之前……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_19"},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"함부로 시간을 동결시킨 건 당신 실수랍니다, 레지나.","JPN":"迂闊に時間を凍結させたのはミスでしたよ、レジーナ。","ENG":"Freezing time so carelessly was your mistake, Regina.","TWN":"隨意凍結時間是你的失誤哦，蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"처음부터 저와 기사님이 노렸던 건, 레지나가 아니었으니까요.","JPN":"最初から私と騎士様の狙いは、レジーナじゃなかったのですから。","ENG":"From the beginning, neither my knight nor I were targeting you.","TWN":"從一開始我和騎士的目標，就不是蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"What...?","TWN":"難道……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"절 너무 원망하지 말아요, 레지나.","JPN":"私を恨まないでくださいね、レジーナ。","ENG":"Do not resent me too much, Regina.","TWN":"別太怨恨我，蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"누구와는 다르게, 저는 제 안의 가아그셰블라의 본질에 충실할 뿐.","JPN":"誰かさんと違って、私は自分の中のガアグシェブラとしての本質に忠実なだけ。","ENG":"Unlike some, I simply remain faithful to the essence of Gha'agsheblah within me.","TWN":"我和某些人不同，只是忠於我體內加格舍夫拉的本質罷了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"애초에 클리포트 게임이 시작되려는데, 클리포트 마왕이 그걸 막을 이유가 없잖아요?","JPN":"そもそも、クリフォトゲームが始まろうとしているのに、クリフォトの魔王がそれを止める理由なんてないじゃないですか。","ENG":"With the Qliphoth Game about to begin, there is no reason for the Qliphoth Demon Lord to stop it.","TWN":"逆卡巴拉遊戲即將開始，逆卡巴拉魔王又怎麼會有阻止它的理由呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그러니까…….","JPN":"ですから……","ENG":"So then...","TWN":"所以……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이제 성찬식을 시작해 볼까요?","JPN":"そろそろ聖餐式を始めましょうか？","ENG":"Shall we begin the feast?","TWN":"現在，就讓我們開始盛宴儀式吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ONLY_FIERCE_ESPR_KNIGHT_HYPER_3"}]`);export{e as default};